        'sister_aria_sprite.png', 'sister_aria_profile.png'
    ],
    MISC: [
        'garrick_standing_sprite.png'
    ]
};

/**
 * 이미지 등 일반 에셋의 URL을 생성합니다.
 */
export const getAssetUrl = (filename: string, folder?: string): string => {
  const baseUrl = 'https://raw.githubusercontent.com/cryingdev/lockharts-forge/sub/assets/';

  let path = filename;
  if (folder) {
    const cleanFolder = folder.endsWith('/') ? folder.slice(0, -1) : folder;
    const cleanFile = filename.startsWith('/') ? filename.slice(1) : filename;
    path = `${cleanFolder}/${cleanFile}`;
  }

  return `${baseUrl}${path}?v=${SESSION_VERSION}`;
};

/**
 * sfx 폴더 내의 오디오 에셋 URL을 생성합니다.
 */
export const getAudioUrl = (filename: string): string => {
  const baseUrl = 'https://raw.githubusercontent.com/cryingdev/lockharts-forge/sub/assets/audio/sfx/';
  const cleanFile = filename.startsWith('/') ? filename.slice(1) : filename;
  return `${baseUrl}${cleanFile}?v=${SESSION_VERSION}`;
};

/**
 * audio/tracks 폴더 내의 음악 트랙 URL을 생성합니다.
 */
export const getMusicUrl = (filename: string): string => {
    const baseUrl = 'https://raw.githubusercontent.com/cryingdev/lockharts-forge/sub/assets/audio/tracks/';
    const cleanFile = filename.startsWith('/') ? filename.slice(1) : filename;
    return `${baseUrl}${cleanFile}?v=${SESSION_VERSION}`;
};

/**
 * Formats a duration in milliseconds to a MM:SS string.
 */
export const formatDuration = (ms: number): string => {
    if (ms <= 0) return '00:00';
    const totalSeconds = Math.floor(ms / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
};

import React, { useEffect, useCallback } from 'react';
import { 
    AUDIO_MANIFEST, 
    IMAGE_MANIFEST, 
    AssetCache, 
    getMusicUrl, 
    getAudioUrl, 
    getAssetUrl 
} from '../utils';

/**
 * AssetManager
 * 앱 시작 시 모든 리소스를 병렬로 로드하여 AssetCache를 채웁니다.
 * 로딩 상태를 전역 이벤트 'asset-loading-progress'로 알립니다.
 */
const AssetManager: React.FC = () => {
    const preloadAll = useCallback(async () => {
        // Audio Context 생성 (디코딩용)
        const AudioCtx = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioCtx();

        const bgms = AUDIO_MANIFEST.BGM;
        const sfxs = AUDIO_MANIFEST.SFX;
        const mercs = IMAGE_MANIFEST.MERCENARIES;
        const misc = (IMAGE_MANIFEST as any).MISC || [];

        const total = bgms.length + sfxs.length + mercs.length + misc.length;
        let loaded = 0;

        const reportProgress = (assetName: string, type: 'Audio' | 'Image') => {
            const progress = Math.round((loaded / total) * 100);
            window.dispatchEvent(new CustomEvent('asset-loading-progress', { 
                detail: { progress, assetName, assetType: type } 
            }));
        };

        // 오디오 로드 및 캐싱
        const loadAudio = async (name: string, type: 'BGM' | 'SFX') => {
            try {
                const url = type === 'BGM' ? getMusicUrl(name) : getAudioUrl(name);
                const response = await fetch(url);
                if (!response.ok) throw new Error(`HTTP ${response.status}`);
                const arrayBuffer = await response.arrayBuffer();
                const audioBuffer = await ctx.decodeAudioData(arrayBuffer);

                AssetCache.audio.set(name, audioBuffer);

                loaded++;
                reportProgress(name, 'Audio');
            } catch (err) {
                console.error(`[AssetLoader] Audio Failed: ${name}`, err);
                loaded++; // 진행률 유지를 위해 카운트는 올림
                reportProgress(name, 'Audio');
            }
        };

        // 이미지 로드 및 캐싱
        const loadImage = (name: string, folder?: string) => {
            return new Promise<void>((resolve) => {
                const img = new Image();
                img.onload = () => {
                    AssetCache.images.set(name, img);
                    loaded++;
                    reportProgress(name, 'Image');
                    resolve();
                };
                img.onerror = () => {
                    console.error(`[AssetLoader] Image Failed: ${name}`);
                    loaded++;
                    reportProgress(name, 'Image');
                    resolve();
                };
                img.src = getAssetUrl(name, folder);
            });
        };

        // 초기화 보고
        window.dispatchEvent(new CustomEvent('asset-loading-progress', { 
            detail: { progress: 0, assetName: 'Initializing Engine...', assetType: 'System' } 
        }));

        // 병렬 실행
        const tasks = [
            ...bgms.map(name => loadAudio(name, 'BGM')),
            ...sfxs.map(name => loadAudio(name, 'SFX')),
            ...mercs.map(name => loadImage(name, 'mercenaries')),
            ...misc.map(name => loadImage(name))
        ];

        await Promise.all(tasks);
        console.log("%c[AssetLoader] All assets internalized.", "color: #10b981; font-weight: bold;");

        // AudioContext 닫기 (디코딩용 임시 컨텍스트)
        if (ctx.state !== 'closed') ctx.close();
    }, []);

    useEffect(() => {
        preloadAll();
    }, [preloadAll]);

    return null;
};

export default AssetManager;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { useGame } from '../context/GameContext';
import { getMusicUrl, getAudioUrl, AssetCache } from '../utils';

interface AudioManagerProps {
    currentView: 'INTRO' | 'TITLE' | 'GAME';
}

/**
 * AudioManager
 * Web Audio API를 사용하여 오디오 재생 및 볼륨 조절을 담당합니다.
 * 리소스는 AssetCache에 프리로드된 데이터를 사용합니다.
 */
const AudioManager: React.FC<AudioManagerProps> = ({ currentView }) => {
    const { state } = useGame();
    const audioSettings = state.settings.audio;
    const activeDungeonId = state.activeManualDungeon?.dungeonId;
    const encounterStatus = state.activeManualDungeon?.encounterStatus;

    const contextRef = useRef<AudioContext | null>(null);
    const bgmGainRef = useRef<GainNode | null>(null);
    const sfxGainRef = useRef<GainNode | null>(null);
    const bgmSourceRef = useRef<AudioBufferSourceNode | null>(null);
    const currentTrackName = useRef<string | null>(null);
    const [isInitialized, setIsInitialized] = useState(false);

    // 1. 현재 상황에 맞는 BGM 트랙 결정
    const targetTrackName = useMemo(() => {
        if (currentView === 'INTRO') return null;
        if (encounterStatus === 'BATTLE') return 'battle_track_01.mp3';
        if (activeDungeonId === 'dungeon_t1_sewers') return 'dungeon_track_01.mp3';
        return 'track_01.mp3';
    }, [currentView, activeDungeonId, encounterStatus]);

    // 2. 오디오 시스템 초기화
    useEffect(() => {
        const AudioCtx = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioCtx();

        const bgmGain = ctx.createGain();
        const sfxGain = ctx.createGain();

        bgmGain.connect(ctx.destination);
        sfxGain.connect(ctx.destination);

        contextRef.current = ctx;
        bgmGainRef.current = bgmGain;
        sfxGainRef.current = sfxGain;

        setIsInitialized(true);

        return () => {
            if (bgmSourceRef.current) {
                try { bgmSourceRef.current.stop(); } catch(e) {}
            }
            if (ctx.state !== 'closed') ctx.close();
        };
    }, []);

    /**
     * BGM 중지 로직
     */
    const stopBgm = useCallback((fadeTime: number = 0.3) => {
        const gainNode = bgmGainRef.current;
        const source = bgmSourceRef.current;
        const ctx = contextRef.current;

        if (source && gainNode && ctx && ctx.state !== 'closed') {
            const currentGain = gainNode.gain.value;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(currentGain, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(0, ctx.currentTime + fadeTime);

            setTimeout(() => {
                try { 
                    if (source && source.buffer) source.stop(); 
                } catch (e) {}
                source.disconnect();
                if (bgmSourceRef.current === source) {
                    bgmSourceRef.current = null;
                    currentTrackName.current = null;
                }
            }, fadeTime * 1000 + 50);
        } else if (source) {
            try { source.stop(); } catch(e) {}
            source.disconnect();
            bgmSourceRef.current = null;
            currentTrackName.current = null;
        }
    }, []);

    /**
     * BGM 재생 시작
     */
    const startBgm = useCallback(async (trackName: string) => {
        const ctx = contextRef.current;
        const gainNode = bgmGainRef.current;
        if (!ctx || !gainNode || ctx.state === 'closed') return;

        if (currentTrackName.current === trackName && bgmSourceRef.current) return;

        stopBgm(0.2); 

        try {
            // AssetCache에서 버퍼 가져오기
            let buffer = AssetCache.audio.get(trackName);

            if (!buffer) {
                // 캐시에 없는 경우 (로딩 지연 등) 런타임 로드 시도
                console.warn(`[Audio] BGM ${trackName} not in cache, fetching manually...`);
                const url = getMusicUrl(trackName);
                const response = await fetch(url);
                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                AssetCache.audio.set(trackName, buffer);
            }

            if (targetTrackName !== trackName) return;

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.loop = true;
            source.connect(gainNode);

            const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
            gainNode.gain.cancelScheduledValues(ctx.currentTime);
            gainNode.gain.setValueAtTime(0, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(effectiveVolume, ctx.currentTime + 0.5);

            if (ctx.state === 'suspended') {
                await ctx.resume().catch(() => {});
            }

            source.start(0);
            bgmSourceRef.current = source;
            currentTrackName.current = trackName;
        } catch (e) {
            console.warn(`[Audio] BGM [${trackName}] play failed:`, e);
        }
    }, [targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, stopBgm]);

    /**
     * SFX 재생 로직
     */
    const playSfx = useCallback(async (filename: string) => {
        const ctx = contextRef.current;
        const gainNode = sfxGainRef.current;
        if (!ctx || !gainNode || ctx.state === 'closed') return;

        if (!audioSettings.masterEnabled || !audioSettings.sfxEnabled) return;

        try {
            let buffer = AssetCache.audio.get(filename);
            if (!buffer) {
                const url = getAudioUrl(filename);
                const response = await fetch(url);
                const arrayBuffer = await response.arrayBuffer();
                buffer = await ctx.decodeAudioData(arrayBuffer);
                AssetCache.audio.set(filename, buffer);
            }

            if (ctx.state === 'suspended') {
                await ctx.resume().catch(() => {});
            }

            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(gainNode);
            source.start(0);
        } catch (e) {
            console.error(`[Audio] SFX [${filename}] error:`, e);
        }
    }, [audioSettings.masterEnabled, audioSettings.sfxEnabled]);

    // BGM 및 설정 감지
    useEffect(() => {
        if (!isInitialized) return;
        const gainNode = bgmGainRef.current;
        const ctx = contextRef.current;
        if (!gainNode || !ctx || ctx.state === 'closed') return;

        const shouldPlay = audioSettings.masterEnabled && audioSettings.musicEnabled && targetTrackName !== null;

        if (shouldPlay) {
            if (currentTrackName.current !== targetTrackName || !bgmSourceRef.current) {
                startBgm(targetTrackName!);
            } else {
                const effectiveVolume = audioSettings.masterVolume * audioSettings.musicVolume;
                gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.1);
            }
        } else {
            stopBgm(0.5);
        }
    }, [isInitialized, targetTrackName, audioSettings.masterVolume, audioSettings.musicVolume, audioSettings.masterEnabled, audioSettings.musicEnabled, startBgm, stopBgm]);

    // SFX 볼륨 업데이트
    useEffect(() => {
        if (!isInitialized) return;
        const gainNode = sfxGainRef.current;
        const ctx = contextRef.current;
        if (gainNode && ctx && ctx.state !== 'closed') {
            const isMuted = !audioSettings.masterEnabled || !audioSettings.sfxEnabled;
            const effectiveVolume = isMuted ? 0 : audioSettings.masterVolume * audioSettings.sfxVolume;
            gainNode.gain.setTargetAtTime(effectiveVolume, ctx.currentTime, 0.05);
        }
    }, [isInitialized, audioSettings.masterVolume, audioSettings.sfxVolume, audioSettings.masterEnabled, audioSettings.sfxEnabled]);

    // SFX 이벤트 리스너
    useEffect(() => {
        const handleSfxRequest = (e: any) => {
            if (e.detail?.file) {
                playSfx(e.detail.file);
            }
        };
        window.addEventListener('play-sfx', handleSfxRequest);
        return () => window.removeEventListener('play-sfx', handleSfxRequest);
    }, [playSfx]);

    // Autoplay 대응
    useEffect(() => {
        const handleInteraction = () => {
            const ctx = contextRef.current;
            if (ctx && ctx.state === 'suspended') {
                ctx.resume().catch(() => {});
            }
        };
        window.addEventListener('mousedown', handleInteraction);
        window.addEventListener('touchstart', handleInteraction);
        return () => {
            window.removeEventListener('mousedown', handleInteraction);
            window.removeEventListener('touchstart', handleInteraction);
        };
    }, []);

    return null;
};

export default AudioManager;

import React, { useEffect, useRef, useState } from 'react';
import Phaser from 'phaser';
import IntroScene from '../game/IntroScene';

interface IntroScreenProps {
  onComplete: () => void;
}

function getViewportSize() {
  const vv = window.visualViewport;
  const w = vv?.width ?? window.innerWidth;
  const h = vv?.height ?? window.innerHeight;
  return { w: Math.floor(w), h: Math.floor(h) };
}

export default function IntroScreen({ onComplete }: IntroScreenProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const gameRef = useRef<Phaser.Game | null>(null);
  const [loadingProgress, setLoadingProgress] = useState(0);

  useEffect(() => {
    const handleProgress = (e: any) => {
        if (typeof e.detail?.progress === 'number') {
            const progress = e.detail.progress;
            const assetName = e.detail.assetName || 'Unknown';
            const assetType = e.detail.assetType || 'Asset';
            setLoadingProgress(progress);

            // 상세 진행률 로그 출력
            console.log(
                `%c[AssetLoader] ${progress}% %c| ${assetType}: ${assetName}`, 
                "color: #fbbf24; font-weight: bold; background: #1c1917; padding: 2px 4px; border-radius: 2px;",
                "color: #78716c; font-weight: normal;"
            );

            if (progress >= 100) {
                console.log(
                    "%c[AssetLoader] INTERNALIZED | All resources mapped to memory. Readiness confirmed.", 
                    "color: #10b981; font-weight: 900; background: #064e3b; padding: 4px 8px; border-radius: 4px; text-transform: uppercase; border: 1px solid #10b981;"
                );
            }
        }
    };
    window.addEventListener('asset-loading-progress', handleProgress);
    return () => window.removeEventListener('asset-loading-progress', handleProgress);
  }, []);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;

    const ensureWrapperSize = () => {
      const { w, h } = getViewportSize();
      el.style.width = `${w}px`;
      el.style.height = `${h}px`;
      el.style.overflow = 'hidden';
      el.style.touchAction = 'none';
      el.style.position = 'relative';
    };

    const resizePhaserToWrapper = () => {
      const game = gameRef.current;
      if (!game) return;
      const rect = el.getBoundingClientRect();
      const w = Math.floor(rect.width);
      const h = Math.floor(rect.height);
      if (w <= 0 || h <= 0) return;
      game.scale.resize(w, h);
      requestAnimationFrame(() => {
        game.scale.refresh();
      });
    };

    let rafId = 0;
    const sync = () => {
      if (rafId) cancelAnimationFrame(rafId);
      rafId = requestAnimationFrame(() => {
        ensureWrapperSize();
        resizePhaserToWrapper();
      });
    };

    const createGameOnce = () => {
      if (gameRef.current) return;
      ensureWrapperSize();
      const rect = el.getBoundingClientRect();
      const w = Math.max(1, Math.floor(rect.width));
      const h = Math.max(1, Math.floor(rect.height));

      const config: Phaser.Types.Core.GameConfig = {
        type: Phaser.AUTO,
        parent: el,
        width: w,
        height: h,
        backgroundColor: '#000000',
        scene: [IntroScene],
        scale: {
          mode: Phaser.Scale.RESIZE,
          autoCenter: Phaser.Scale.CENTER_BOTH,
        },
      };

      console.log("[Intro] Initializing cinematic engine...");
      const game = new Phaser.Game(config);
      gameRef.current = game;

      const onIntroComplete = () => {
          console.log("%c[Intro] Sequence concluded. Navigating to title.", "color: #8b5cf6; font-weight: bold;");
          onComplete();
      };
      game.events.on('intro-complete', onIntroComplete);

      sync();
      setTimeout(sync, 80);
      setTimeout(sync, 180);

      return () => {
        game.events.off('intro-complete', onIntroComplete);
        game.destroy(true);
        gameRef.current = null;
      };
    };

    let cancelled = false;
    const waitForSizeAndCreate = () => {
      if (cancelled) return;
      ensureWrapperSize();
      const rect = el.getBoundingClientRect();
      if (rect.width > 0 && rect.height > 0) {
        return createGameOnce();
      }
      requestAnimationFrame(waitForSizeAndCreate);
    };

    const gameCleanup = waitForSizeAndCreate();

    const vv = window.visualViewport;
    const onOrientationChange = () => {
      sync();
      setTimeout(sync, 100);
      setTimeout(sync, 250);
      setTimeout(sync, 450);
    };

    vv?.addEventListener('resize', sync);
    window.addEventListener('resize', sync);
    window.addEventListener('orientationchange', onOrientationChange);

    const ro = new ResizeObserver(() => sync());
    ro.observe(el);

    sync();

    return () => {
      cancelled = true;
      if (rafId) cancelAnimationFrame(rafId);
      ro.disconnect();
      vv?.removeEventListener('resize', sync);
      window.removeEventListener('resize', sync);
      window.removeEventListener('orientationchange', onOrientationChange);
      if (typeof gameCleanup === 'function') gameCleanup();
    };
  }, [onComplete]);

  const isComplete = loadingProgress >= 100;

  return (
    <div className="fixed inset-0 bg-black z-50 overflow-hidden touch-none">
      <div ref={containerRef} />

      {/* Asset Loading Progress Bar Overlay */}
      <div className={`absolute bottom-8 left-1/2 -translate-x-1/2 w-48 md:w-64 flex flex-col items-center gap-2 transition-opacity duration-1000 ${isComplete ? 'opacity-0' : 'opacity-100'}`}>
        <div className="flex justify-between w-full px-1">
            <span className="text-[8px] font-black text-amber-500/60 uppercase tracking-widest">Internalizing Assets</span>
            <span className="text-[8px] font-mono font-bold text-amber-500/80">{loadingProgress}%</span>
        </div>
        <div className="w-full h-1 bg-stone-900 rounded-full border border-white/5 overflow-hidden shadow-inner">
            <div 
                className="h-full bg-amber-500 transition-all duration-300 shadow-[0_0_8px_rgba(245,158,11,0.5)]" 
                style={{ width: `${loadingProgress}%` }}
            />
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { GameProvider } from './context/GameContext';
import IntroScreen from './components/IntroScreen';
import TitleScreen from './components/TitleScreen';
// Fix: Use default import for MainGameLayout as it is exported as default in its source file
import MainGameLayout from './components/MainGameLayout';
import { getNextAvailableSlot } from './utils/saveSystem';
import { GameState } from './types/game-state';
// Moved useGame import from line 72 to the top of the file
import { useGame } from './context/GameContext';
import AudioManager from './components/AudioManager';
import AssetManager from './components/AssetManager';

type GameView = 'INTRO' | 'TITLE' | 'GAME';

const App = () => {
  const [view, setView] = useState<GameView>('INTRO');
  const [pendingLoadState, setPendingLoadState] = useState<GameState | null>(null);
  const [activeSlotIndex, setActiveSlotIndex] = useState<number>(0);

  const handleIntroComplete = () => {
      setView('TITLE');
  };

  const handleNewGame = () => {
      const nextSlot = getNextAvailableSlot();
      setActiveSlotIndex(nextSlot);
      setPendingLoadState(null);
      setView('GAME');
  };

  const handleLoadGame = useCallback((data: GameState, slotIndex: number) => {
      if (data) {
          setActiveSlotIndex(slotIndex);
          setPendingLoadState(data);
          setView('GAME');
      } else {
          alert("Failed to load save data!");
      }
  }, []);

  const handleQuitToTitle = () => {
      setView('TITLE');
      setPendingLoadState(null);
  };

  // 게임 진행 중 로드 요청 시 호출되는 함수
  const handleLoadFromSettings = (data: GameState, slotIndex: number) => {
      // 1. 먼저 타이틀 화면으로 나가서 기존 게임 인스턴스를 파괴
      setView('TITLE');

      // 2. 다음 프레임에서 새로운 데이터로 게임 시작
      setTimeout(() => {
          handleLoadGame(data, slotIndex);
      }, 50);
  };

  return (
      <GameProvider initialSlotIndex={activeSlotIndex}>
        <AssetManager />
        <AudioManager currentView={view} />

        {view === 'INTRO' && <IntroScreen onComplete={handleIntroComplete} />}

        {view === 'TITLE' && <TitleScreen onNewGame={handleNewGame} onLoadGame={handleLoadGame} />}

        {view === 'GAME' && (
            <GameLoader initialData={pendingLoadState}>
                <MainGameLayout onQuit={handleQuitToTitle} onLoadFromSettings={handleLoadFromSettings} />
            </GameLoader>
        )}
      </GameProvider>
  );
};

/**
 * GameLoader 컴포넌트:
 * GameProvider 내부에서 실행되어, 로드할 데이터가 있는 경우 상태를 즉시 교체합니다.
 */
const GameLoader: React.FC<{ initialData: GameState | null, children: React.ReactNode }> = ({ initialData, children }) => {
    const { actions } = useGame();
    const isFirstRun = React.useRef(true);

    useEffect(() => {
        if (isFirstRun.current && initialData) {
            actions.loadGame(initialData);
        }
        isFirstRun.current = false;
    }, [initialData, actions]);

    return <>{children}</>;
};

export default App;

